var e=JSON.parse(`[{"id":"L3_1","type":"dialog","speaker":"SILKY_NPC_ESPR2_NULL","text":{"KOREA":"와아…… 밖에서 봤을 때는 허름했는데 안은 무척 아름다워요.","JPN":"わあ……外から見た時は古びて見えましたけど、中はとても美しいですね。","ENG":"Wow... It looked so run-down on the outside, but the inside is beautiful.","TWN":"哇啊……從外面看破破爛爛的，裡面卻好漂亮啊。"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SILKY_NPC_ESPR2_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"TRUMPET_HARMONY_ESPR2_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L4_1","type":"dialog","speaker":"TRUMPET_HARMONY_ESPR2_NULL","text":{"KOREA":"여기가 발렌티누스 수도원인가? 음침하게 사는 줄 알았더니 영 딴판이네.","JPN":"ここがバレンチヌス修道院？　薄暗い感じで生活してるのかと思ったら全然違うんだね。","ENG":"Is this the Valentinus Monastery? I imagined it would be creepier than this.","TWN":"這裡就是聖華倫修道院嗎？我還以為會很陰森，結果正好相反呢。"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SILKY_NPC_ESPR2_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"TRUMPET_HARMONY_ESPR2_NULL","face":"UNIT_IDLE"}}}},{"id":"L6_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"어차피 겉만 그럴싸할 뿐이겠죠. 뒤에서는 무슨 음험한 짓을 저지르고 있을지 모릅니다.","JPN":"どうせ外見がそれらしいだけでしょう。裏ではどんな陰険なことをしているかわかりませんわ。","ENG":"Do not be fooled by its exterior. We do not know what insidious activities are happening behind those walls.","TWN":"反正只是外表看起來還不錯而已吧。不知道在背後搞什麼鬼。"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"큭…….","JPN":"くっ……","ENG":"Kgh...","TWN":"呃……"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"힘들어 보이는군. 실키 양 때문에 부상을 숨기려는 건가?","JPN":"辛そうだな。シルキー君のために怪我を隠しているのかね？","ENG":"You don't look so good. Were you hiding your pain because of Sylkie?","TWN":"你看起來很難受。是因為思琪，才故意隱瞞傷勢嗎？"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"잠시라도 괜찮으니, 쉬는 편이 좋겠네만.","JPN":"少しの間だけでも、休んだ方がよさそうだが。","ENG":"I think you should rest, even for a little while.","TWN":"哪怕是一下也好，你還是休息一下比較好。"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"……걱정해 주셔서 고맙지만, 아직 버틸 수 있어요.","JPN":"……ご心配してくださるのは感謝しますが、まだ耐えられますわ。","ENG":"...Thank you for your consideration, but I can handle myself.","TWN":"……謝謝你擔心我，不過我還能撐住。"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"제가 약한 모습을 보이면 그 음험한 작자들이 무슨 짓을 할지 모르니까요.","JPN":"私が弱い姿を見せれば、あの陰険な者たちが何をしてくるかわかりませんから。","ENG":"If I show any signs of weakness to them, those insidious ones might jump at the opportunity.","TWN":"如果我露出軟弱的一面，不知道那些陰險的傢伙，又會做出什麼事來。"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"NUN_NPC_ESPR2_NULL","text":{"KOREA":"후훗, 말씀이 심하시네. 음험하기로는 맥크레디 가문에 견줄 곳이 없을 텐데.","JPN":"ふふっ、酷いわね。陰険さでいったらマクレディー家に敵うところはないないはずだけど。","ENG":"Ha ha. That's a little harsh. If you're talking insidious, then the MacCready family is none to compare.","TWN":"呵呵，這話說得太過分了。要說陰險，誰也比不上麥克蕾蒂家族。"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NUN_NPC_ESPR2_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"루나, 혹시 수도원에서 왔다던 사람이 저 분인가요?","JPN":"ルナさん、修道院から来たという人はあの方ですか？","ENG":"Luna, is this the person who came from the monastery?","TWN":"露娜，你說的從修道院來的人是她嗎？"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"TRUMPET_HARMONY_ESPR2_NULL","text":{"KOREA":"응. 아그네스 아비게일. 분명 자기가 종교학부장이라고 했어.","JPN":"うん。アグネス・アビゲイル。確か宗教学部長だって言ってた。","ENG":"Uh-huh. Agnes Abigail. She said that she was the Dean of Religion.","TWN":"嗯，艾格妮絲·亞比該，她說自己是宗教學院院長。"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"TRUMPET_HARMONY_ESPR2_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L19_1","type":"dialog","speaker":"AGNES_ESPR_NULL_NULL","text":{"KOREA":"오랜만이야, 부학회장님. 숲에 풀어 둔 파수견들 때문에 많이 놀랐지?","JPN":"久しぶりね、副学会長。森に放っておいた番犬のせいでずいぶんと驚いたでしょう？","ENG":"Long time no see, Ms. Vice President. Were you startled by the guard dogs in the forest?","TWN":"好久不見，副學會長。森林裡的守衛犬嚇到你了吧？"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGNES_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"AGNES_ESPR_NULL_NULL","text":{"KOREA":"종을 더 일찍 울렸어야 했는데 미안해. 고해소를 정리하느라 확인이 늦었거든.","JPN":"もっと早くに鐘を鳴らすべきだったのに、ごめんなさいね。告解部屋を片付けていたら確認が遅れてしまって。","ENG":"My apologies. I should've rung the bell sooner, but I was preoccupied with organizing the confessions.","TWN":"我應該早點敲鐘的，對不起。我忙著收拾告解室，所以這麼晚才發現。"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGNES_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"AGNES_ESPR_NULL_NULL","text":{"KOREA":"따라와. 부상을 치료해 줄게.","JPN":"ついてきて。怪我を治療してあげる。","ENG":"Come with me. I will treat your wounds.","TWN":"跟我來，我會為你治療。"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGNES_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"SILKY_NPC_ESPR2_NULL","text":{"KOREA":"부학회장님, 저 분이랑 아는 사이셨어요?","JPN":"副学会長様、あの方とお知り合いだったんですか？","ENG":"Vice President, do you know this person?","TWN":"副學會長，你認識那個人嗎？"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SILKY_NPC_ESPR2_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L25_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"아뇨…. 아무리 기억을 되짚어 봐도 처음 뵙는 분이에요.","JPN":"いいえ……どう考えても初めて会う方ですわ。","ENG":"No... I have no recollection of her in my memories.","TWN":"不認識……不管我怎麼回想，我跟她應該是第一次見面。"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SILKY_NPC_ESPR2_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L27_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"그래도 지금은 저 사람 말을 따르는 편이 좋겠군.","JPN":"だが、今はあの人の言葉に従った方がよさそうだ。","ENG":"Nevertheless, I believe listening to her is best here.","TWN":"不過現在還是照著那個人說的去做比較好。"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SILKY_NPC_ESPR2_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L28_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"가뜩이나 쇠약해진 몸으로 부상까지 내버려 두면 더 악화될 걸세.","JPN":"ただでさえ衰弱しているのに、怪我まで放置したらもっと悪化するぞ。","ENG":"You're already weak as is, but leaving your wounds untreated will only worsen your state.","TWN":"你的身體本來就很虛弱了，再放任傷口不管的話，傷勢會變得更嚴重。"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SILKY_NPC_ESPR2_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L29_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"……그렇네요. 적어도 당장 저희를 해코지할 생각은 없어 보이니까요.","JPN":"……そうですわね。少なくとも今すぐ私たちに害をなすつもりはないようですから。","ENG":"...Very well. Also, I do not see any hostility towards us right now.","TWN":"……是啊。她看起來至少現在不會害我們。"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SILKY_NPC_ESPR2_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L32_1","type":"dialog","speaker":"AGNES_ESPR_NULL_NULL","text":{"KOREA":"이걸로 응급 처치는 끝. 약이 남아 있어서 다행이네.","JPN":"はい、これで応急手当は終わり。薬が残っていてよかったわ。","ENG":"This should be enough for now. Thank goodness we had some ointment left.","TWN":"這樣就做好應急措施了。幸好還有藥。"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGNES_ESPR_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"TRUMPET_HARMONY_ESPR2_NULL","text":{"KOREA":"이 에그타르트 엄청 맛있다! 더 없어?","JPN":"このエッグタルト、めっちゃおいしい！　もっとない？","ENG":"Whoa! This egg tart is sooo good! Do you have any more?","TWN":"這個蛋撻超好吃！還有嗎？"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"TRUMPET_HARMONY_ESPR2_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L35_1","type":"dialog","speaker":"SILKY_NPC_ESPR2_NULL","text":{"KOREA":"자, 잘 먹었습니다….","JPN":"ご、ごちそうさまでした……","ENG":"Th-that was delicious...","TWN":"我…我吃飽了……"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SILKY_NPC_ESPR2_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"TRUMPET_HARMONY_ESPR2_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L37_1","type":"dialog","speaker":"AGNES_ESPR_NULL_NULL","text":{"KOREA":"우리 수도원의 명물이니까. 아쉽지만 오늘치는 방금 먹은 게 전부야.","JPN":"この修道院の名物だからね。残念だけど、今日の分は今ので終わりよ。","ENG":"That's our monastery's special egg tart. But unfortunately, that was the last batch for today.","TWN":"這是我們修道院的招牌。不過很可惜，今天的配額剛才都被你們吃完了。"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGNES_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"흠. 굉장히 독특한 재료를 쓴 것 같군.","JPN":"ふむ。ずいぶんと変わった材料を使っているようだな。","ENG":"Hmm... Seems like you used some interesting ingredients.","TWN":"嗯，好像用了非常獨特的材料。"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGNES_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"AGNES_ESPR_NULL_NULL","text":{"KOREA":"후훗. 귀엽게 생겨선 의심이 많네. 안에 어떤 분이 들어앉아 계시길래 그럴까?","JPN":"ふふっ。可愛い見かけの割に疑い深いのね。中にいったい誰が入っているのかしら？","ENG":"Ha ha. A lot of doubt coming from such a cute-looking machine. I'm curious to know who is controlling you.","TWN":"呵呵，沒想到你長得這麼可愛，疑心病卻很重。是因為裡面住著什麼厲害的人嗎？"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGNES_ESPR_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"……","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"AGNES_ESPR_NULL_NULL","text":{"KOREA":"왜 그래, 부학회장님? 에그타르트가 입맛에 안 맞아?","JPN":"どうしたの？　副学会長。エッグタルトが口に合わない？","ENG":"What's wrong, Ms. Vice President? Do you not like the taste?","TWN":"怎麼了，副學會長？蛋撻不合口味嗎？"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGNES_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"아뇨. 혹시 저희 어디서 뵌 적 있던가요?","JPN":"いいえ。もしかして、どこかでお会いしましたか？","ENG":"Fine. Anyway, have we met before?","TWN":"不是，我們以前是不是在哪兒見過？"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"AGNES_ESPR_NULL_NULL","text":{"KOREA":"설마 잊은 거야? 조금 섭섭해지는걸.","JPN":"まさか忘れちゃったの？　ちょっと寂しいわね。","ENG":"Have you forgotten about me already? That's a little upsetting.","TWN":"你不會忘了吧？這樣我會很難過呢。"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGNES_ESPR_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"AGNES_ESPR_NULL_NULL","text":{"KOREA":"영지에서 회동을 가질 때도 난 부학회장님 편을 들어 줬다고 생각했는데.","JPN":"領地で会合をした時も副学会長の味方をしてあげたつもりだったんだけど。","ENG":"Don't you remember that I sided with you at the last estate meeting?","TWN":"在領地召開會議的時候，我可是站在副學會長這邊呢。"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGNES_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"회동이라니요? 그런 자리가 있었나요?","JPN":"会合？　そんな場、あったでしょうか？","ENG":"A meeting? Was there a meeting of some sort?","TWN":"會議？有過那種事嗎？"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SILKY_NPC_ESPR2_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L50_1","type":"dialog","speaker":"SILKY_NPC_ESPR2_NULL","text":{"KOREA":"네. 학부장님들이랑 수행원 분들이 오셔서 며칠 동안 영지가 북적거렸어요.","JPN":"はい。学部長様とお付きの方々がいらっしゃって、数日は領地が賑やかでした。","ENG":"Yes. The estate was bustling for days with many of the deans and followers attending.","TWN":"是的，學院院長們及隨行人員都來了，那幾天領地裡很熱鬧。"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SILKY_NPC_ESPR2_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L1_1","type":"dialog","speaker":"SILKY_NPC_ESPR2_NULL","text":{"KOREA":"헛간 지붕이 사라지거나 사람 얼굴 달린 개가 나타나는 사건들이 잔뜩 일어나기도 했고요.","JPN":"物置小屋の屋根が消えたり、人面犬が現れたりする事件がたくさん起きましたし。","ENG":"Of course, there were some minor incidents as well. Such as a barn's roof suddenly disappearing or even a dog with the face of a man appearing.","TWN":"還發生了很多倉庫屋頂消失，或長著人臉的狗出現的事件。"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SILKY_NPC_ESPR2_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L2_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"잠깐, 제 어머니가 학회장이었던 시절과 착각한 거 아닌가요?","JPN":"待ってください、私の母が学会長だった頃と勘違いしているのではないですか？","ENG":"Hold on. Are you not mistaking the time for when Mother was president?","TWN":"等等，你是不是把現在的我，和母親擔任學會長的時期搞混了？"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SILKY_NPC_ESPR2_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L3_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"전 고향에 돌아온 지도 얼마 안 된 데다가, 그런 소란이 일어났다면 몰랐을 리도 없어요.","JPN":"私は故郷に帰って間もないし、そんな騒動が起きたら知らないはずがありません。","ENG":"It has not been long since I returned to the estate, and even if there was a meeting, I would have known if such accidents had occurred.","TWN":"我才回到家鄉沒多久，而且如果發生了這種騷亂，我不可能不知道。"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SILKY_NPC_ESPR2_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L5_1","type":"dialog","speaker":"TRUMPET_HARMONY_ESPR2_NULL","text":{"KOREA":"무슨 소리야. 네가 1408호에 온 지 얼마나 오래됐는데.","JPN":"何言ってるんだよ。あんたが1408号に来てどれだけ経ったと思ってんの？","ENG":"What are you talking about? You've been staying at room 1408 for quite a long time now.","TWN":"你在說什麼啊。你來到1408號都多久了。"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TRUMPET_HARMONY_ESPR2_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"그럴 리가……","JPN":"そんなはず……","ENG":"That cannot be...","TWN":"怎麼可能……"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"위화감을 느낀 지점이 바로 그 부분이었군.","JPN":"違和感を覚えたのはその部分だったのか。","ENG":"So this is where you felt a sense of discordance.","TWN":"最有違和感的地方就是這個。"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"아무래도 맥크레디 양은 기억에 혼선이 온 모양이야.","JPN":"どうやらマクレディー君の記憶に混乱が生じたようだな。","ENG":"I believe Regina is conflating memories.","TWN":"看來麥克蕾蒂的記憶有點混亂。"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"AGNES_ESPR_NULL_NULL","text":{"KOREA":"후훗. 귀엽게 생겨선 날카로운 지적이네.","JPN":"ふふっ。見かけは可愛いくせに指摘は鋭いわね。","ENG":"Ha ha. What a keen observation from such a cute bird.","TWN":"呵呵，長得這麼可愛，說話很犀利呢。"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"AGNES_ESPR_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L13_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"기억에 혼선이 왔다고요? 제가?","JPN":"記憶に混乱？　私が？","ENG":"Me? Conflating memories?","TWN":"記憶混亂嗎？我？"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_DESPAIR"},"R":{"char_id":"AGNES_ESPR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"확실히 영지에 대해서도 사장님이 질문하셨을 때야 떠오르긴 했지만……","JPN":"確かに領地のことについても社長が質問して初めて思い出したりしたのですが……","ENG":"When you asked about the estate, it certainly came to mind, but...","TWN":"雖然我確實是在老闆問到領地的時候，才想起很多事……"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"AGNES_ESPR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"그럼 기억 상실? 치매의 전조?","JPN":"それでは記憶喪失？　痴呆症の前兆？","ENG":"Then am I losing my memories? A sign of dementia?","TWN":"難道我失憶了？還是癡呆的前兆？"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_SURPRISE"},"R":{"char_id":"AGNES_ESPR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"어떡하죠? 불구가 되면 모를까, 공부도 못하는 백치가 되는 건 상상도 하기 싫어요.","JPN":"どうしましょう？　障害ならともかく、勉強もできないバカになるのは想像もしたくありませんわ。","ENG":"What should I do? I do not mind being disabled, but I refuse to become an idiot who knows nothing...!","TWN":"怎麼辦？殘廢了還好說，變成不能學習的白癡，我甚至想都不敢想。"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"AGNES_ESPR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L18_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"침착하게나. 병이라고 단정 짓기에는 아직 일러.","JPN":"落ち着きたまえ。病気だと断定するにはまだ早い。","ENG":"Calm down. It's too early to determine if it's an illness or not.","TWN":"你冷靜點。現在就斷定是疾病，還為時過早。"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"AGNES_ESPR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L19_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"기억이 누락되거나 사라지진 않았으니, 심리적인 이유일 가능성이 높을 걸세.","JPN":"記憶が欠落したり消えたわけではないから、心理的な要因である可能性が高いだろう。","ENG":"You haven't lost or forgotten any memories, so the problem is likely to be psychological.","TWN":"記憶並沒有缺失或消失，說明是心理原因的可能性比較大。"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"AGNES_ESPR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L20_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"사장님 말씀은… 제가 무의식적으로 학회에 대한 일을 떠올리기 싫어한다는 건가요?","JPN":"つまり……私が無意識に学会についてのことを思い出したくないと思っていると？","ENG":"What you are saying is... that my subconscious is refusing to recall memories about the Society?","TWN":"老闆的意思是……我下意識地不願記起學會的事嗎？"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_DESPAIR"},"R":{"char_id":"AGNES_ESPR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L21_1","type":"dialog","speaker":"AGNES_ESPR_NULL_NULL","text":{"KOREA":"맞아. 나도 짚이는 이유가 있거든.","JPN":"そうよ。私にも心当たりがあるわ。","ENG":"Correct. I have my reasons too.","TWN":"沒錯，因為我也有猜想的理由。"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGNES_ESPR_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"AGNES_ESPR_NULL_NULL","text":{"KOREA":"어쩌면 생각대로 일이 잘 안 풀려서 쌓인 스트레스 때문일지도?","JPN":"もしかしたら仕事が思いどおりにいかなくて溜まったストレスのせいかも？","ENG":"Perhaps it is all the stress from things not working out as you planned?","TWN":"或許是因為事情不像你想的那樣順利，然後壓力日積月累導致的吧？"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGNES_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"스트레스?","JPN":"ストレス？","ENG":"Stress?","TWN":"壓力？"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"AGNES_ESPR_NULL_NULL","text":{"KOREA":"응. 처음 봤을 때 직감했어. 새로운 부학회장님은 사서 고생을 할 상이라고.","JPN":"ええ。初めて会った時にピンときたの。新しい副学会長は進んで苦労するタイプだってね。","ENG":"Yes. I had a hunch when I first saw you. You're the type of person who just asks for trouble.","TWN":"嗯，第一次見你的時候我就有種直覺。新的副學會長會自討苦吃。"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGNES_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"AGNES_ESPR_NULL_NULL","text":{"KOREA":"덕분에 모처럼 다들 모인 자리도… 그렇게 화기애애하진 않았지.","JPN":"おかげでせっかく一同が会した場だったけど……あまりいい雰囲気ではなかったわ。","ENG":"Thanks to that, the meeting itself wasn't so... \\"inviting\\" to say the least.","TWN":"托你的福，大家難得聚到一起……卻也沒那麼和氣。"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGNES_ESPR_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}}]`);export{e as default};